<?php require __DIR__.'/../includes/bootstrap.php'; header('Content-Type: application/json'); if(!Security::rateLimit('api', App::config('security.rate_limit.max',120), App::config('security.rate_limit.window',60))){http_response_code(429); echo json_encode(['error'=>'rate_limited']); exit;} $path=parse_url($_SERVER['REQUEST_URI'],PHP_URL_PATH); if(str_ends_with($path,'/videos')) echo json_encode(['data'=>(new Video())->latest(20)]); else { http_response_code(404); echo json_encode(['error'=>'not_found']); }
